import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../context/AuthContext';
import AnimatedBackground from '../components/common/AnimatedBackground';
import toast from 'react-hot-toast';

function StrengthBar({ password }) {
  const checks = [
    { label: '8+ chars', ok: password.length >= 8 },
    { label: 'Uppercase', ok: /[A-Z]/.test(password) },
    { label: 'Number', ok: /[0-9]/.test(password) },
    { label: 'Special', ok: /[^A-Za-z0-9]/.test(password) }
  ];
  const score = checks.filter(c => c.ok).length;
  const colors = ['#ef4444','#f59e0b','#6366f1','#10b981'];
  return (
    <div style={{ marginTop: 8 }}>
      <div style={{ display: 'flex', gap: 5, marginBottom: 7 }}>
        {[0,1,2,3].map(i => (
          <div key={i} style={{ flex: 1, height: 3, borderRadius: 99, background: i < score ? colors[score - 1] : 'rgba(255,255,255,0.08)', transition: 'background 0.3s' }} />
        ))}
      </div>
      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
        {checks.map(c => (
          <span key={c.label} style={{ fontSize: 11, padding: '2px 8px', borderRadius: 99, background: c.ok ? 'rgba(16,185,129,0.15)' : 'rgba(255,255,255,0.06)', color: c.ok ? '#10b981' : 'rgba(255,255,255,0.3)', transition: 'all 0.25s' }}>
            {c.ok ? '✓' : '○'} {c.label}
          </span>
        ))}
      </div>
    </div>
  );
}

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [showPwd, setShowPwd] = useState(false);
  const [errors, setErrors] = useState({});
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const validate = () => {
    const e = {};
    if (!email) e.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(email)) e.email = 'Enter a valid email';
    if (!password) e.password = 'Password is required';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async (ev) => {
    ev.preventDefault();
    if (!validate()) return;
    const result = await login(email, password, rememberMe);
    if (result.success) {
      toast.success('Welcome back! 🎉');
      navigate('/dashboard');
    } else {
      toast.error(result.error);
      setErrors({ api: result.error });
    }
  };

  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20, position: 'relative', background: '#060611' }}>
      <AnimatedBackground particles={25} />

      <motion.div style={{ width: '100%', maxWidth: 420, position: 'relative', zIndex: 10 }}
        initial={{ opacity: 0, y: 40 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.55, ease: [0.4,0,0.2,1] }}>

        {/* Logo */}
        <motion.div style={{ textAlign: 'center', marginBottom: 32 }}
          animate={{ y: [0, -8, 0] }} transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut' }}>
          <div style={{ width: 64, height: 64, background: 'linear-gradient(135deg, #6366f1, #ec4899)', borderRadius: 18, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 14px', fontSize: 28, fontWeight: 800, fontFamily: "'Syne',sans-serif", color: '#fff', boxShadow: '0 8px 32px rgba(99,102,241,0.5)' }}>
            E
          </div>
          <div style={{ fontFamily: "'Syne',sans-serif", fontSize: 26, fontWeight: 800, background: 'linear-gradient(135deg, #818cf8, #ec4899)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            EmpAxis Pro
          </div>
          <div style={{ color: 'rgba(240,238,255,0.45)', fontSize: 13, marginTop: 5 }}>Enterprise Employee Management</div>
        </motion.div>

        {/* Card */}
        <div style={{ background: 'rgba(13,12,29,0.85)', backdropFilter: 'blur(24px)', border: '1px solid rgba(99,102,241,0.2)', borderRadius: 24, padding: 36, boxShadow: '0 32px 80px rgba(0,0,0,0.6)', position: 'relative', overflow: 'hidden' }}>
          {/* shimmer top line */}
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 2, background: 'linear-gradient(90deg, transparent, #6366f1, #ec4899, transparent)' }} />

          <h2 style={{ fontFamily: "'Syne',sans-serif", fontSize: 20, fontWeight: 800, marginBottom: 6 }}>Sign In</h2>
          <p style={{ color: 'rgba(240,238,255,0.45)', fontSize: 13, marginBottom: 26 }}>Enter your credentials to continue</p>

          <AnimatePresence>
            {errors.api && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}
                style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.25)', borderRadius: 10, padding: '10px 14px', marginBottom: 18, fontSize: 13, color: '#ef4444' }}>
                {errors.api}
              </motion.div>
            )}
          </AnimatePresence>

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="admin@company.com"
                className={`form-input ${errors.email ? 'error' : ''}`} autoComplete="email" />
              {errors.email && <div className="form-error">{errors.email}</div>}
            </div>

            <div className="form-group">
              <label className="form-label">Password</label>
              <div style={{ position: 'relative' }}>
                <input type={showPwd ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter your password"
                  className={`form-input ${errors.password ? 'error' : ''}`} style={{ paddingRight: 42 }} autoComplete="current-password" />
                <button type="button" onClick={() => setShowPwd(s => !s)} style={{ position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(240,238,255,0.4)', fontSize: 16 }}>
                  {showPwd ? '🙈' : '👁️'}
                </button>
              </div>
              {password && <StrengthBar password={password} />}
              {errors.password && <div className="form-error">{errors.password}</div>}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24 }}>
              <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: 13.5 }}>
                <input type="checkbox" checked={rememberMe} onChange={e => setRememberMe(e.target.checked)} style={{ accentColor: '#6366f1', width: 16, height: 16 }} />
                Remember me
              </label>
            </div>

            <motion.button type="submit" disabled={loading} className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', padding: '12px', fontSize: 15 }}
              whileTap={{ scale: 0.97 }}>
              {loading ? <><span style={{ display:'inline-block', width:16, height:16, border:'2px solid rgba(255,255,255,0.3)', borderTopColor:'#fff', borderRadius:'50%', animation:'spin 0.8s linear infinite', marginRight:8 }} />Signing in...</> : 'Sign In →'}
            </motion.button>
          </form>

          <div style={{ marginTop: 24, padding: 14, background: 'rgba(99,102,241,0.06)', border: '1px solid rgba(99,102,241,0.15)', borderRadius: 10 }}>
            <div style={{ fontSize: 11.5, color: 'rgba(240,238,255,0.4)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 600 }}>Demo Credentials</div>
            <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 12.5, color: '#818cf8' }}>admin@company.com</div>
            <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 12.5, color: '#ec4899' }}>Admin@123</div>
          </div>
        </div>
      </motion.div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}
